// Multi-provider model router
// Priority: Gemini free tier → Claude Sonnet → Claude Opus
const input = $input.all()[0].json;

const modelMap = {
  // FREE TIER — use for most tasks
  'gemini-free': {
    provider: 'google',
    model_id: 'gemini-2.0-flash',
    max_tokens: 8192,
    cost_per_1k_input: 0,
    cost_per_1k_output: 0
  },
  'gemini-pro': {
    provider: 'google',
    model_id: 'gemini-2.5-pro-preview-05-06',
    max_tokens: 8192,
    cost_per_1k_input: 0,
    cost_per_1k_output: 0
  },
  // PAID — only for high-value analytical work
  'sonnet': {
    provider: 'anthropic',
    model_id: 'claude-sonnet-4-6',
    max_tokens: 4096,
    cost_per_1k_input: 0.003,
    cost_per_1k_output: 0.015
  },
  'opus': {
    provider: 'anthropic',
    model_id: 'claude-opus-4-6',
    max_tokens: 8192,
    cost_per_1k_input: 0.015,
    cost_per_1k_output: 0.075
  }
};

// Default to gemini-free if no model specified
const modelKey = input.model || 'gemini-free';
const config = modelMap[modelKey] || modelMap['gemini-free'];

return [{
  json: {
    ...input,
    provider: config.provider,
    model_id: config.model_id,
    max_tokens: config.max_tokens,
    cost_per_1k_input: config.cost_per_1k_input,
    cost_per_1k_output: config.cost_per_1k_output,
    model_key: modelKey,
    retry_count: 0,
    max_retries: 3
  }
}];

// Parse Gemini response into unified format
const response = $input.all()[0].json;
const body = response.body || response;

const content = body.candidates?.[0]?.content?.parts?.[0]?.text || '';
const inputTokens = body.usageMetadata?.promptTokenCount || 0;
const outputTokens = body.usageMetadata?.candidatesTokenCount || 0;

// Gemini free tier = $0
const inputCost = 0;
const outputCost = 0;

// Try to parse JSON from response
let parsedContent = content;
try {
  const jsonMatch = content.match(/```json\n([\s\S]*?)\n```/) || content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsedContent = JSON.parse(jsonMatch[1] || jsonMatch[0]);
  }
} catch (e) {
  // Keep as string if not valid JSON
}

const routerData = $('Model Router').first().json;

return [{
  json: {
    content: content,
    parsed_content: parsedContent,
    model: routerData.model_id,
    provider: 'google',
    input_tokens: inputTokens,
    output_tokens: outputTokens,
    input_cost: '0.000000',
    output_cost: '0.000000',
    total_cost: '0.000000',
    workflow_name: routerData.workflow_name,
    client_name: routerData.client_name,
    purpose: routerData.purpose,
    timestamp: new Date().toISOString()
  }
}];

// Parse Claude response into unified format
const response = $input.all()[0].json;
const body = response.body || response;

const content = body.content?.[0]?.text || '';
const inputTokens = body.usage?.input_tokens || 0;
const outputTokens = body.usage?.output_tokens || 0;

const routerData = $('Model Router').first().json;
const inputCost = inputTokens * routerData.cost_per_1k_input / 1000;
const outputCost = outputTokens * routerData.cost_per_1k_output / 1000;

// Try to parse JSON from response
let parsedContent = content;
try {
  const jsonMatch = content.match(/```json\n([\s\S]*?)\n```/) || content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsedContent = JSON.parse(jsonMatch[1] || jsonMatch[0]);
  }
} catch (e) {}

return [{
  json: {
    content: content,
    parsed_content: parsedContent,
    model: routerData.model_id,
    provider: 'anthropic',
    input_tokens: inputTokens,
    output_tokens: outputTokens,
    input_cost: inputCost.toFixed(6),
    output_cost: outputCost.toFixed(6),
    total_cost: (inputCost + outputCost).toFixed(6),
    workflow_name: routerData.workflow_name,
    client_name: routerData.client_name,
    purpose: routerData.purpose,
    timestamp: new Date().toISOString()
  }
}];

// Retry logic with exponential backoff
const input = $input.all()[0].json;
const retryCount = (input.retry_count || 0) + 1;
const maxRetries = input.max_retries || 3;

if (retryCount > maxRetries) {
  throw new Error(`API failed after ${maxRetries} retries (provider: ${input.provider}). Last error: ${JSON.stringify(input)}`);
}

const backoffMs = Math.pow(2, retryCount) * 1000;
await new Promise(resolve => setTimeout(resolve, backoffMs));

return [{
  json: {
    ...input,
    retry_count: retryCount
  }
}];
